arguments.new_str:
var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// Fixed: CacheService must be scoped — a singleton capturing a scoped service
// throws at startup in .NET 9 (ValidateScopes is now enforced by default).
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// Fixed: ConfigureHttpMessageHandlerBuilder was removed in .NET 9.
// Use ConfigurePrimaryHttpMessageHandler<THandler> instead.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler<HttpClientHandler>(handler =>
    {
        handler.UseCookies = false;
    });
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
});
// Fixed: .NET 9 redacts header values in Trace-level logs by default.
// Allow the headers you need to debug behind the reverse proxy.
builder.Services.AddHttpLogging(options =>
{
    options.RequestHeaders.Add("X-Forwarded-For");
    options.RequestHeaders.Add("X-Forwarded-Proto");
    options.RequestHeaders.Add("X-Forwarded-Host");
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

